        return False
    l_sorted = sorted(l)
    for i in range(n - 2):
        if i > 0 and l_sorted[i] == l_sorted[i - 1]:
            continue
        left, right = i + 1, n - 1
        while left < right:
            total = l_sorted[i] + l_sorted[left] + l_sorted[right]
            if total == 0:
                return True
            elif total < 0:
